# Usage: source_db_analyzer <source_db_type> <database_name> <execution_mode> <queries_file_path> <query_result_file_path> <pattern_analysis_days> <max_query_results> <aws_cluster_arn> <aws_secret_arn> <aws_region> <hostname> <port> <output_dir>
source_db_analyzer() {
